const body = $input.first().json.body || $input.first().json;

// Template types available
const templates = {
  'best_for_audience': {
    title_pattern: 'Best {product_type} for {audience}',
    slug_pattern: 'best-{product_type_slug}-for-{audience_slug}',
    intent: 'commercial_investigation',
    description: 'Targets buyers comparing options for their specific use case'
  },
  'audience_tools': {
    title_pattern: '{audience} Productivity Templates and Tools',
    slug_pattern: '{audience_slug}-productivity-templates',
    intent: 'informational',
    description: 'Broad audience-specific resource pages'
  },
  'free_vs_paid': {
    title_pattern: 'Free vs Paid {product_type}: Which Is Worth It?',
    slug_pattern: 'free-vs-paid-{product_type_slug}',
    intent: 'commercial_investigation',
    description: 'High-intent comparison searches — your paid product wins'
  },
  'how_to_choose': {
    title_pattern: 'How to Choose the Right {product_type} for {use_case}',
    slug_pattern: 'how-to-choose-{product_type_slug}-{use_case_slug}',
    intent: 'informational',
    description: 'Positions you as expert, funnels to product recommendations'
  }
};

// Audiences to target
const audiences = [
  'freelancers', 'solopreneurs', 'coaches', 'consultants', 'content creators',
  'virtual assistants', 'photographers', 'graphic designers', 'copywriters',
  'social media managers', 'project managers', 'small business owners',
  'Etsy sellers', 'course creators', 'podcast hosts', 'YouTubers',
  'real estate agents', 'personal trainers', 'nutritionists', 'therapists'
];

// Product types
const productTypes = [
  'Notion template', 'productivity planner', 'business template',
  'content calendar', 'client management system', 'invoice template',
  'goal tracker', 'habit tracker', 'project planner', 'budget template'
];

// Use cases
const useCases = [
  'managing clients', 'tracking projects', 'planning content',
  'running a business', 'staying organized', 'saving time',
  'growing on social media', 'managing finances'
];

const templateType = body.template_type || 'best_for_audience';
const batchSize = Math.min(body.batch_size || 5, 10); // Max 10 per run
const batchOffset = body.batch_offset || 0;
const template = templates[templateType] || templates.best_for_audience;
const productCategory = body.product_category || 'productivity templates';

// Generate keyword combinations for this batch
const combinations = [];
for (const audience of audiences) {
  for (const productType of productTypes) {
    combinations.push({ audience, product_type: productType, use_case: useCases[Math.floor(Math.random() * useCases.length)] });
  }
}

// Pick the batch
const batchItems = combinations.slice(batchOffset, batchOffset + batchSize);

return batchItems.map(item => ({
  json: {
    template_type: templateType,
    template_config: template,
    audience: item.audience,
    product_type: item.product_type,
    use_case: item.use_case,
    product_category: productCategory,
    page_title: template.title_pattern
      .replace('{product_type}', item.product_type)
      .replace('{audience}', item.audience)
      .replace('{use_case}', item.use_case),
    page_slug: template.slug_pattern
      .replace('{product_type_slug}', item.product_type.toLowerCase().replace(/[^a-z0-9]+/g, '-'))
      .replace('{audience_slug}', item.audience.toLowerCase().replace(/[^a-z0-9]+/g, '-'))
      .replace('{use_case_slug}', item.use_case.toLowerCase().replace(/[^a-z0-9]+/g, '-')),
    search_intent: template.intent,
    brand_url: 'https://clearstackstudio.com',
    store_url: 'https://clearstackstudio.com/shop',
    batch_offset: batchOffset
  }
}));

const raw = $input.first().json;
const keyword = $('⚙️ Generate Keyword Batch').first().json;

let pageData;
try {
  const content = raw?.message?.content || raw?.response || '';
  const match = content.match(/```json\n?([\s\S]*?)\n?```/) || content.match(/({[\s\S]*})/);
  pageData = JSON.parse((match ? match[1] || match[0] : content).trim());
} catch(e) {
  pageData = { error: true, content_html: `<p>Error generating page: ${e.message}</p>` };
}

// Build FAQPage schema from the FAQ pairs
const faqSchema = pageData.faq_pairs?.length ? {
  '@context': 'https://schema.org',
  '@type': 'FAQPage',
  'mainEntity': pageData.faq_pairs.map(q => ({
    '@type': 'Question',
    'name': q.question,
    'acceptedAnswer': { '@type': 'Answer', 'text': q.answer }
  }))
} : null;

// Build full page content with schema
const schemaHtml = faqSchema 
  ? `<script type="application/ld+json">${JSON.stringify(faqSchema)}</script>\n`
  : '';

const fullContent = schemaHtml + (pageData.content_html || '');

// WordPress page payload
return [{ json: {
  title: pageData.page_title || keyword.page_title,
  slug: keyword.page_slug,
  content: fullContent,
  excerpt: pageData.excerpt || '',
  status: 'publish',
  parent: 0,
  template: 'seo-landing.php',
  meta: {
    _yoast_wpseo_title: pageData.page_title,
    _yoast_wpseo_metadesc: pageData.meta_description,
    _yoast_wpseo_focuskw: pageData.focus_keyword,
    _seo_page_type: 'programmatic',
    _target_audience: keyword.audience,
    _target_product: keyword.product_type
  },
  keyword_data: keyword,
  word_count: pageData.word_count || 0,
  faq_count: pageData.faq_pairs?.length || 0
}}];
